    public DbSet<Carrier> Carriers { get; set; }
    public DbSet<Company> Companies { get; set; }
    public DbSet<CompanySignatory> CompanySignatories { get; set; }
    public DbSet<Container> Containers { get; set; }
    public DbSet<Country> Countries { get; set; }
    public DbSet<CountryOfOrigin> CountryOfOrigins { get; set; }
    public DbSet<KittingBom> KittingBoms { get; set; }
    public DbSet<Port> Ports { get; set; }
    public DbSet<Product> Products { get; set; }
    public DbSet<ProductPrice> ProductPrices { get; set; }
    public DbSet<Destination> Destinations { get; set; }
    public DbSet<Customer> Customers { get; set; }
    public DbSet<TxAuditLog> AuditLogs { get; set; }
    public DbSet<TxSalesOrder> SalesOrders { get; set; }
